namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }

    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes = GetSeedRecipes();
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public List<RecipeCategory> GetCategories() =>
    [
        new() { Name = "Breakfast", Icon = "🥞", Description = "Start your morning right" },
        new() { Name = "Lunch", Icon = "🥗", Description = "Midday meals and salads" },
        new() { Name = "Dinner", Icon = "🍝", Description = "Hearty evening dishes" },
        new() { Name = "Desserts", Icon = "🍰", Description = "Sweet treats and baked goods" },
        new() { Name = "Snacks", Icon = "🍿", Description = "Quick bites and appetizers" },
        new() { Name = "Drinks", Icon = "🥤", Description = "Smoothies, cocktails, and more" },
    ];

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    private static List<Recipe> GetSeedRecipes() =>
    [
        new()
        {
            Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
            Description = "Fluffy golden pancakes perfect for a lazy weekend morning.",
            Ingredients = ["2 cups flour", "2 eggs", "1½ cups milk", "2 tbsp sugar", "2 tsp baking powder", "¼ tsp salt", "3 tbsp melted butter"],
            Steps = ["Mix dry ingredients in a bowl.", "Whisk eggs, milk, and melted butter together.", "Combine wet and dry ingredients until just mixed.", "Pour batter onto a hot greased griddle.", "Cook until bubbles form, then flip and cook until golden."],
            TotalRatings = 12, RatingSum = 52
        },
        new()
        {
            Id = 2, Title = "Avocado Toast", Category = "Breakfast",
            Description = "Simple, trendy, and delicious — topped with everything seasoning.",
            Ingredients = ["2 slices sourdough bread", "1 ripe avocado", "1 tbsp lemon juice", "Salt and pepper", "Red pepper flakes", "Everything bagel seasoning"],
            Steps = ["Toast the bread until golden and crispy.", "Mash avocado with lemon juice, salt, and pepper.", "Spread mashed avocado on toast.", "Sprinkle with red pepper flakes and everything seasoning."],
            TotalRatings = 8, RatingSum = 35
        },
        new()
        {
            Id = 3, Title = "Caesar Salad", Category = "Lunch",
            Description = "A crisp romaine salad with creamy Caesar dressing and croutons.",
            Ingredients = ["1 head romaine lettuce", "½ cup Caesar dressing", "¼ cup shaved parmesan", "1 cup croutons", "2 anchovy fillets (optional)", "Freshly ground black pepper"],
            Steps = ["Wash and chop romaine into bite-sized pieces.", "Toss lettuce with Caesar dressing.", "Add croutons and shaved parmesan.", "Top with anchovy fillets if desired.", "Season with black pepper and serve."],
            TotalRatings = 6, RatingSum = 25
        },
        new()
        {
            Id = 4, Title = "Spaghetti Bolognese", Category = "Dinner",
            Description = "A rich and hearty Italian meat sauce served over spaghetti.",
            Ingredients = ["400g spaghetti", "500g ground beef", "1 onion, diced", "3 cloves garlic", "400g crushed tomatoes", "2 tbsp tomato paste", "1 tsp oregano", "Salt and pepper", "Parmesan for serving"],
            Steps = ["Cook spaghetti according to package directions.", "Brown ground beef in a large pan, then drain excess fat.", "Sauté onion and garlic until softened.", "Add crushed tomatoes, tomato paste, and oregano.", "Simmer sauce for 20 minutes.", "Serve sauce over spaghetti with parmesan."],
            TotalRatings = 15, RatingSum = 68
        },
        new()
        {
            Id = 5, Title = "Chocolate Chip Cookies", Category = "Desserts",
            Description = "Chewy, gooey cookies loaded with chocolate chips.",
            Ingredients = ["2¼ cups flour", "1 cup butter, softened", "¾ cup sugar", "¾ cup brown sugar", "2 eggs", "1 tsp vanilla", "1 tsp baking soda", "½ tsp salt", "2 cups chocolate chips"],
            Steps = ["Preheat oven to 375°F (190°C).", "Cream butter and sugars until fluffy.", "Beat in eggs and vanilla.", "Mix in flour, baking soda, and salt.", "Fold in chocolate chips.", "Drop spoonfuls onto baking sheets.", "Bake 9–11 minutes until golden edges."],
            TotalRatings = 20, RatingSum = 94
        },
        new()
        {
            Id = 6, Title = "Guacamole", Category = "Snacks",
            Description = "Fresh and zesty guacamole — perfect with tortilla chips.",
            Ingredients = ["3 ripe avocados", "1 lime, juiced", "½ cup diced onion", "1 jalapeño, seeded and minced", "¼ cup cilantro, chopped", "1 diced tomato", "Salt and pepper"],
            Steps = ["Mash avocados in a bowl to desired consistency.", "Stir in lime juice, onion, jalapeño, cilantro, and tomato.", "Season with salt and pepper.", "Serve immediately with tortilla chips."],
            TotalRatings = 10, RatingSum = 43
        },
        new()
        {
            Id = 7, Title = "Mango Smoothie", Category = "Drinks",
            Description = "A creamy tropical smoothie bursting with mango flavor.",
            Ingredients = ["1 cup frozen mango chunks", "1 banana", "½ cup yogurt", "½ cup orange juice", "1 tbsp honey"],
            Steps = ["Add all ingredients to a blender.", "Blend until smooth and creamy.", "Pour into a glass and serve immediately."],
            TotalRatings = 7, RatingSum = 30
        },
        new()
        {
            Id = 8, Title = "Grilled Chicken Wrap", Category = "Lunch",
            Description = "A protein-packed wrap with grilled chicken and fresh veggies.",
            Ingredients = ["2 chicken breasts", "2 large flour tortillas", "1 cup mixed greens", "½ cup diced tomatoes", "¼ cup ranch dressing", "½ cup shredded cheese"],
            Steps = ["Season and grill chicken until cooked through.", "Slice chicken into strips.", "Warm tortillas in a dry pan.", "Layer greens, chicken, tomatoes, cheese, and dressing.", "Roll up tightly and slice in half."],
            TotalRatings = 9, RatingSum = 38
        },
    ];
}

