using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes = GetSeedRecipes();
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public List<RecipeCategory> GetCategories() =>
    [
        new() { Name = "Breakfast", Icon = "🥞", Description = "Start your morning right" },
        new() { Name = "Lunch", Icon = "🥗", Description = "Midday meals and salads" },
        new() { Name = "Dinner", Icon = "🍝", Description = "Hearty evening dishes" },
        new() { Name = "Desserts", Icon = "🍰", Description = "Sweet treats and baked goods" },
        new() { Name = "Snacks", Icon = "🍿", Description = "Quick bites and appetizers" },
        new() { Name = "Drinks", Icon = "🥤", Description = "Smoothies, cocktails, and more" },
    ];

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
