@page "/category/{CategoryName}"
@using RecipeHub.Services

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info mt-3">No recipes in this category yet. <a href="/submit">Be the first to add one!</a></div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4 mt-2">
        @foreach (var recipe in Recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">
                            <a href="/recipe/@recipe.Id">@recipe.Title</a>
                        </h5>
                        <p class="card-text text-muted">@recipe.Description</p>
                        <small class="text-warning">
                            @for (int i = 1; i <= 5; i++)
                            {
                                @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                            }
                            <span class="text-muted ms-1">(@recipe.TotalRatings ratings)</span>
                        </small>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private List<RecipeHub.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{RecipeId:int}"
@using RecipeHub.Services

<PageTitle>@(Recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (Recipe is not null)
        {
            <li class="breadcrumb-item"><a href="/category/@Uri.EscapeDataString(Recipe.Category)">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        }
    </ol>
</nav>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="lead text-muted">@Recipe.Description</p>

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header fw-bold">🧾 Ingredients</div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8">
            <h4>📝 Steps</h4>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in Recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <div class="card mt-2 mb-4">
        <div class="card-body">
            <h5 class="card-title">Rate this Recipe</h5>
            <p class="text-muted mb-2">
                Average: @Recipe.AverageRating.ToString("0.0") / 5
                (@Recipe.TotalRatings ratings)
            </p>
            <StarRating RecipeId="Recipe.Id" />
        </div>
    </div>
}

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private RecipeHub.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetRecipeById(RecipeId);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services

<div class="d-inline-block" style="cursor: pointer; font-size: 1.5rem;">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span @onclick="() => SubmitRating(star)"
              @onmouseover="() => HoverStar = star"
              @onmouseout="() => HoverStar = 0"
              class="@(i <= DisplayStars ? "text-warning" : "text-secondary")">
            @(i <= DisplayStars ? "★" : "☆")
        </span>
    }
</div>

@if (Submitted)
{
    <div class="text-success mt-1">
        <small>Thanks for rating! You gave @SubmittedStars star@(SubmittedStars != 1 ? "s" : "").</small>
    </div>
}

@code {
    [Parameter, EditorRequired] public int RecipeId { get; set; }
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private int HoverStar { get; set; }
    private int SubmittedStars { get; set; }
    private bool Submitted { get; set; }

    private int DisplayStars => HoverStar > 0 ? HoverStar : SubmittedStars;

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        SubmittedStars = stars;
        Submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<strong>@SubmittedTitle</strong>" has been added.
        <a href="/recipe/@SubmittedId">View it here</a> or <button class="btn btn-link p-0" @onclick="ResetForm">submit another</button>.
    </div>
}
else
{
    <EditForm Model="FormModel" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="FormModel.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
            <ValidationMessage For="() => FormModel.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="FormModel.Category" class="form-select">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat.Name">@cat.Icon @cat.Name</option>
                }
            </InputSelect>
            <ValidationMessage For="() => FormModel.Category" />
        </div>

        <div class="mb-3">
            <label for="description" class="form-label">Short Description</label>
            <InputTextArea id="description" @bind-Value="FormModel.Description" class="form-control" rows="2"
                           placeholder="A brief description of your recipe" />
            <ValidationMessage For="() => FormModel.Description" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="FormModel.IngredientsText" class="form-control" rows="5"
                           placeholder="One ingredient per line&#10;e.g.&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => FormModel.IngredientsText" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="FormModel.StepsText" class="form-control" rows="5"
                           placeholder="One step per line&#10;e.g.&#10;Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients and stir." />
            <ValidationMessage For="() => FormModel.StepsText" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel FormModel { get; set; } = new();
    private bool SubmitSuccess { get; set; }
    private string SubmittedTitle { get; set; } = string.Empty;
    private int SubmittedId { get; set; }

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = FormModel.Title,
            Category = FormModel.Category,
            Description = FormModel.Description,
            Ingredients = FormModel.IngredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = FormModel.StepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        RecipeService.AddRecipe(recipe);
        SubmittedTitle = recipe.Title;
        SubmittedId = recipe.Id;
        SubmitSuccess = true;
    }

    private void ResetForm()
    {
        FormModel = new();
        SubmitSuccess = false;
    }
}

