toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community.</p>

@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<strong>@SubmittedTitle</strong>" has been added.
        <a href="/recipe/@SubmittedId">View it here</a> or <button class="btn btn-link p-0" @onclick="ResetForm">submit another</button>.
    </div>
}
else
{
    <EditForm Model="FormModel" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="FormModel.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
            <ValidationMessage For="() => FormModel.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="FormModel.Category" class="form-select">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat.Name">@cat.Icon @cat.Name</option>
                }
            </InputSelect>
            <ValidationMessage For="() => FormModel.Category" />
        </div>

        <div class="mb-3">
            <label for="description" class="form-label">Short Description</label>
            <InputTextArea id="description" @bind-Value="FormModel.Description" class="form-control" rows="2"
                           placeholder="A brief description of your recipe" />
            <ValidationMessage For="() => FormModel.Description" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="FormModel.IngredientsText" class="form-control" rows="5"
                           placeholder="One ingredient per line&#10;e.g.&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => FormModel.IngredientsText" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="FormModel.StepsText" class="form-control" rows="5"
                           placeholder="One step per line&#10;e.g.&#10;Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients and stir." />
            <ValidationMessage For="() => FormModel.StepsText" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    [Inject] public RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel FormModel { get; set; } = new();
    private bool SubmitSuccess { get; set; }
    private string SubmittedTitle { get; set; } = string.Empty;
    private int SubmittedId { get; set; }

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = FormModel.Title,
            Category = FormModel.Category,
            Description = FormModel.Description,
            Ingredients = FormModel.IngredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = FormModel.StepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        RecipeService.AddRecipe(recipe);
        SubmittedTitle = recipe.Title;
        SubmittedId = recipe.Id;
        SubmitSuccess = true;
    }

    private void ResetForm()
    {
        FormModel = new();
        SubmitSuccess = false;
    }
}

using System.ComponentModel.DataAnnotations;

namespace RecipeHub.Models;

public class RecipeFormModel
{
    [Required(ErrorMessage = "Please enter a recipe title.")]
    [StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a category.")]
    public string Category { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please enter a short description.")]
    [StringLength(300, MinimumLength = 10, ErrorMessage = "Description must be between 10 and 300 characters.")]
    public string Description { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please list at least one ingredient.")]
    [MinLength(3, ErrorMessage = "Please list at least one ingredient.")]
    public string IngredientsText { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please describe at least one step.")]
    [MinLength(3, ErrorMessage = "Please describe at least one step.")]
    public string StepsText { get; set; } = string.Empty;
}

